  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"jeju-eastern-unesco-spots-day-tour","locale":"en","product_id":"jeju-eastern-unesco-spots-day-tour","seo":{"pageTitle":"Jeju Eastern UNESCO Spots Small-Group Day Tour | AtoC Korea","metaDescription":"9-hour small-group eastern Jeju loop: Hamdeok Beach, Seongeup Folk Village (UNESCO), Micheon lava cave, Seongsan Ilchulbong (UNESCO), Haenyeo Museum. 4.9/5.","primaryKeywords":["Jeju eastern UNESCO tour","Seongsan Ilchulbong tour","Seongeup Folk Village tour","Haenyeo Museum tour","Jeju Sunrise Peak day tour"],"ogImage":"https://www.visitjeju.net/image/main/2024/seongsan-ilchulbong.jpg","title":"Jeju Eastern UNESCO Spots Day Tour · 9-hour Small-Group · All Admissions Included"},"catalog_card":{"thumbnail":"https://www.visitjeju.net/image/main/2024/seongsan-ilchulbong.jpg","title":"Jeju Eastern UNESCO Spots Day Tour","priceLabel":"Price varies — confirm at booking","shortCardDescription":"A small-group day tour covering eastern Jeju''s UNESCO and signature stops in a single 9-hour loop — Hamdeok Seoubong Beach, Seongeup Folk Village, the Micheon Cave lava tube system (current alternate to closed Manjanggul), Seongsan Ilchulbong (UNESCO Sunrise Peak), and the Haenyeo Museum dedicated to Jeju''s UNESCO-listed women divers. ALL admissions included; certified English/Chinese-speaking guide; rated 4.9/5 across 1,148 reviews.","tags":["small_group","jeju","east_jeju","unesco","value_priced","all_admissions_included"],"rating":4.9,"reviewCount":1148,"slug":"jeju-eastern-unesco-spots-day-tour","subtitle":"Small-group mini-coach with English/Chinese guide — 9-hour eastern Jeju loop covering Hamdeok, Seongeup, Micheon Cave, Seongsan UNESCO crater, and the Haenyeo Museum.","region":"Eastern Jeju","duration":"9 hours","stopsCount":8,"badges":["Small group","Jeju","East Jeju","UNESCO","Value priced","All admissions included"],"heroImage":"https://www.visitjeju.net/image/main/2024/seongsan-ilchulbong.jpg"},"headlineLine1":"Sunrise Peak to lava tube, beach to women-diver museum —","headlineLine2":"eastern Jeju''s UNESCO loop, all admissions included","price":{"amountLabel":"","currency":"USD","per":"person","priceSource":"getyourguide_t608456","priceNote":"Small-group price not yet confirmed from listing snippet. Sister product (Southern UNESCO, same operator) is $43 per person; this Eastern tour is comparable. Once confirmed, AtoC Korea sale price applies a flat 10% discount.","discountPercent":10},"hero":{"imageUrl":"https://www.visitjeju.net/image/main/2024/seongsan-ilchulbong.jpg","imagePosition":"center 35%","tagline":"The most reviewed eastern Jeju tour — 4.9/5 across 1,148 reviews, all admissions included","pills":["small_group","jeju"],"meta":{"duration":"≈ 9 hours (08:30 first pickup, ≈ 18:00 drop-off)","region":"Eastern Jeju","stops":"8 stops","rating":4.9,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"details","label":"Details"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reviews"}],"glanceItems":[{"icon":"clock","label":"Duration","value":"≈ 9 hours (first pickup 08:30, drop-off ≈ 18:00)"},{"icon":"users","label":"Group","value":"Small group, mini-coach with English/Chinese-speaking guide"},{"icon":"map-pin","label":"Pickup","value":"Ocean Suites 08:30 / Jeju Airport Gate 1 (1F) 08:45 / LOTTE City 08:55 / Shilla Duty-Free 09:05"},{"label":"Rating","value":"4.9/5 across 1,148 reviews — operator''s most reviewed Jeju tour"},{"icon":"footprints","label":"Walking","value":"Moderate — Seongsan Ilchulbong climb (optional), folk village paths, cave stairs"},{"icon":"ticket","label":"Includes","value":"Vehicle, certified guide, ALL admissions. Excludes: lunch (≈ ₩15,000), tips"}],"galleryItems":[{"id":"g1","type":"photo","src":"https://www.visitjeju.net/image/main/2024/seongsan-ilchulbong.jpg","alt":"Emerald-blue water and white sand at Hamdeok Seoubong Beach","caption":"Seongsan Ilchulbong (Sunrise Peak) — UNESCO Natural Heritage","location":"Hamdeok-ri, Jocheon-eup, Jeju","atmosphere":"Coastal opener"},{"id":"g2","type":"photo","src":"https://images.unsplash.com/photo-1601471569526-2c7d5e1b7e5f?w=1200","alt":"Stone-walled thatched houses inside Seongeup Folk Village","caption":"Hamdeok Seoubong Beach — emerald shallows and the Seoubong volcanic cone","location":"Seongeup, Pyoseon-myeon, Seogwipo","atmosphere":"600-year Joseon-era folk village"},{"id":"g3","type":"photo","src":"https://images.unsplash.com/photo-1502175353174-a7a44e84da10?w=1200","alt":"Illuminated lava tube interior at Micheon Cave, Ilchul Land","caption":"Seongeup Folk Village — preserved volcanic-stone walls and thatched roofs","location":"Ilchul Land, Pyoseon-myeon","atmosphere":"Indoor lava-tube break"},{"id":"g4","type":"photo","src":"https://images.unsplash.com/photo-1535139262971-c51845709a48?w=1200","alt":"View from Seongsan Ilchulbong UNESCO crater rim across the East Sea","caption":"Micheon Cave lava tube (current alternate to closed Manjanggul)","location":"Seongsan Ilchulbong UNESCO World Heritage Site","atmosphere":"Day centerpiece — crater climb"},{"id":"g5","type":"photo","src":"https://images.unsplash.com/photo-1599946347371-68eb71b16afc?w=1200","alt":"Haenyeo diving equipment display at Jeju Haenyeo Museum","caption":"Haenyeo Museum — celebrating Jeju''s UNESCO-listed women divers","location":"Hado-ri, Gujwa-eup, Jeju","atmosphere":"UNESCO Intangible Cultural Heritage"}],"itineraryStops":[{"number":1,"time":"09:00","duration":"30 min","name":"Pickup (4 points across Jeju City)","category":"Pickup — Jeju City Hotel/Hub Sequence","description":"**Pickup is consolidated at four central Jeju City points** to minimize morning crisscrossing: **Jeju International Airport (제주공항)** for guests with same-day arrivals or hotels near the airport corridor; **Jeju City Hall (제주시청)** for guests in the Yeon-dong / Nohyeong / Old Town hotel cluster; **Hagwi-dong (하귀동)** as the westernmost pickup before heading east; and **Dongmun Traditional Market (동문시장)** as the optional eastern Jeju City pickup near Tapdong waterfront. Sequence is Hagwi → Airport → City Hall → Dongmun → eastward Route 1132 toward Hamdeok. The minicoach is **small-group (max ~14 pax)** with English-speaking guide. **Bilingual printed itinerary card** distributed at pickup, weather brief at first stop.","image":"https://images.unsplash.com/photo-1513475382585-d06e58bcb0e0","highlights":["**4 pickup points** across Jeju City — Airport, City Hall, Hagwi, Dongmun","Sequence west→east minimizes morning coach distance","**Small-group minicoach (max 14 pax)** with English guide","Bilingual itinerary card + weather brief at first stop","Total morning transit Jeju City → Hamdeok: ~40 min","Drop-off mirrors pickup with optional Dongmun Market end-of-day stop"],"timeUsed":["Hagwi pickup ~09:00 — 5 min","Airport pickup ~09:10 — 5 min","City Hall pickup ~09:20 — 5 min","Dongmun pickup ~09:30 — 5 min","Eastbound Route 1132 to Hamdeok — ~30 min"],"whyOnRoute":"Four pickup points cover Jeju City''s main hotel + transport zones (airport, mid-city, old town, market district) without forcing guests across the city. Sequencing west→east lands the coach at Hamdeok ~09:50 — early enough to catch the morning low-tide beach panorama before peak visitor flow."},{"number":2,"time":"≈ 09:50","duration":"60 min","name":"Hamdeok Seoubong Beach","category":"Top-3 Jeju Beach — Olle Trail 19 + WWII Coastal History","description":"**Hamdeok Seoubong Beach (함덕 서우봉 해변)** is consistently ranked among **Jeju''s top 3 beaches**, defined by the contrast between **white-sand beach (~500 m main stretch, 3 connected coves totaling ~900 m)** and the **adjacent volcanic cone Seoubong (서우봉, ''Cow Looking Like a Cow''s Head'' parasitic cone)** rising directly from the eastern end. The water''s signature **emerald-turquoise color** comes from shallow coral-sand seabed reflecting through clear ocean — the Mediterranean-like contrast (rare in Korea) is what made Hamdeok one of the country''s most photographed domestic beach destinations. The beach can absorb up to **50,000 daily visitors** at peak summer, but spring + autumn visits are typically uncrowded. **Seoubong Peak** (climbable ~1 hour to summit) wears **canola-yellow slopes in spring (March–April)** and offers a **panoramic eastward view to Manjanggul lava-tube area**. **Historical layer**: the sea cliffs immediately west of Seoubong hold **Imperial Japanese Army tunnels carved during WWII colonial occupation** — kamikaze suicide-boat shelters and ammunition stores, similar to the 18 caves at Seongsan Ilchulbong. The tunnels are publicly accessible (with signage explaining the historical context). The beach is the **central segment of Jeju Olle Trail Course 19 (조천 → 김녕)**, marked with the trail''s signature blue-orange ribbons. **Cafe Delmoondo (델문도 카페)** anchors the beachfront — large terraces, sea-view, popular for Instagram and casual stops. **FREE admission**; the beach is **20 km / ~40-min drive from Jeju International Airport** on Route 1132.","image":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e","highlights":["**Top 3 Jeju beaches** — emerald-turquoise water + white coral sand","**500 m main beach** + 3 connected coves (~900 m total length)","**Seoubong volcanic cone** ~1-hour summit climb — canola-yellow slopes March–April","**WWII Imperial Japanese Army tunnels** in adjacent cliffs — kamikaze suicide-boat shelters","**Olle Trail Course 19 (조천 → 김녕)** — blue-orange ribbon trail markers","**Cafe Delmoondo** — large terraces, beachfront, signature stop","Up to **50,000 daily summer visitors** at peak; uncrowded spring + autumn","**FREE admission**; 20 km / ~40 min from Jeju International Airport","Mediterranean-like color contrast — rare on the Korean Peninsula"],"timeUsed":["Coach arrival + parking — ~5 min","Beach walk (main stretch + 2nd cove) — ~25 min","WWII tunnel exteriors viewing — ~10 min","Cafe Delmoondo or beachfront photography — ~15 min","Buffer / regroup — ~5 min"],"whyOnRoute":"**Coastal opening anchor of the eastern UNESCO route**. Hamdeok establishes the day''s first dual frame: **natural beauty (top-3 beach) + WWII colonial history (tunnels)** — a deliberate setup for the day''s recurring pattern of **paired natural + historical layers** (continuing at Seongsan with its 18 caves, and at the Haenyeo Museum where diving heritage meets UNESCO Intangible designation). Geographically, Hamdeok is the **natural first stop after Jeju City**, just 40 min east on Route 1132, before the long inland transit to Seongeup. Compared with **Woljeongri Beach (further east, no WWII history)** or **Iho Tewoo Beach (Jeju City, no Olle trail anchor)**, Hamdeok is **on-route, FREE, and historically layered** — the highest-yield east-coast beach stop. Morning timing also catches the **9:50–10:50 low-flat lighting** before midday harshness.","_poi_meta":{"poi_key":"hamdeok_seoubong_beach","kb_version":"1.19","verified_date":"2026-04-29","sources":["Jeju Olle Foundation — Trail Course 19 official map","VisitJeju — Hamdeok Seoubong Beach","Jeju 4·3 Peace Foundation — Imperial Japanese Army tunnel records","Korea Tourism Organization — Top 3 Jeju Beaches ranking","Jocheon-eup local cultural office — Seoubong oreum trail records"]}},{"number":3,"time":"≈ 11:00","duration":"60 min","name":"Seongeup Folk Village (UNESCO heritage)","category":"Joseon-era Walled Town — Important Folklore Cultural Heritage (1423 founding)","description":"**Seongeup Folk Village (성읍 민속마을)** is a **living Joseon-era walled town founded in 1423** during the reign of **Sejong the Great** as Jeong-eui-hyeon (정의현), one of the three administrative seats of Joseon-era Jeju. The village served continuously as a **county administrative center until 1914** — nearly **500 years** — and retains **110 traditional structures** today within the original eupseong (읍성) walled-town footprint, designed on **Korean feng shui principles** typical of Joseon county capitals. The entire village is designated **Important Folklore Cultural Heritage of South Korea**, with **multiple individual buildings** carrying separate heritage status. At the village center stand **two ancient trees designated Natural Monuments of South Korea** — a **Saw-leaf Zelkova (느티나무)** and a **Japanese Hackberry (팽나무)**, both estimated **600+ years old** and revered as the village''s spiritual anchor. Historical scars are visible: a **major fire in 1826 destroyed ~80 buildings**, and the village suffered fire damage **during the Jeju Uprising in 1948** — both events preserved as historical record on village signage. The **peak household count (historical, pre-modern) was ~1,500** — today the village remains inhabited by ~250 families, many actively maintaining traditional crafts. Drama filming credit: **''Dae Jang Geum (Jewel in the Palace)'' (MBC, 2003–2004)**, the international K-drama hit. Local specialty: **Omegisul (오메기술)** — a **rice-based traditional Jeju liquor** brewed by **one family for multiple generations**, with the brewing demonstrated and tasted free of charge at the home-brewery within the village. **FREE admission**; outdoor walking dominates (~70% outdoor / 30% indoor for individual hanok visits).","image":"https://images.unsplash.com/photo-1517400508447-f8dd518b86db","highlights":["**Founded 1423** by Sejong the Great — administrative center until **1914 (~500 years)**","**110 traditional structures** within original eupseong walled-town footprint","**Important Folklore Cultural Heritage of South Korea** (entire village + multiple buildings)","**Two ~600-year-old trees** at center: Saw-leaf Zelkova + Japanese Hackberry — **Natural Monuments**","Designed on **Joseon Korean feng shui (geomancy) principles** — typical county-capital plan","**''Dae Jang Geum'' (MBC 2003–2004)** filming location — international K-drama hit","**Omegisul (오메기술)** — rice-based Jeju liquor brewed by single family for generations (free tasting)","Historical scars: **1826 fire** destroyed ~80 buildings; **1948 Jeju Uprising** damage","**FREE admission** — village still inhabited by ~250 families maintaining traditions"],"timeUsed":["Parking + welcome brief by village docent — ~10 min","Walk to ancient trees + village center — ~10 min","Hanok interior visits (2–3 representative homes) — ~15 min","Omegisul brewery free tasting — ~10 min","Olle alley walk + photography — ~10 min","Buffer — ~5 min"],"whyOnRoute":"**Mid-morning UNESCO-heritage anchor** — and the day''s first explicit Korean cultural heritage layer (continuing the morning''s natural + colonial-history framing from Hamdeok). Where the nature-core sister tour places Seongeup as the day''s closing anchor (16:50 golden-hour light), this UNESCO-spots route uses Seongeup as the **11:00 mid-morning narrative pivot** — guests transition from the morning''s coastal history (Hamdeok WWII) to the inland 600-year Joseon administrative heritage before lunch. The Important Folklore Cultural Heritage designation + Natural Monument trees + 1423 founding all reinforce the day''s UNESCO-and-heritage framing. The hour dwell window is sufficient for a docent-guided alley walk + ancient tree photography + optional Omegisul tasting; coach then continues 20 min east to Ilchulland.","_poi_meta":{"poi_key":"seongeup_folk_village","kb_version":"1.19","verified_date":"2026-04-29","sources":["Cultural Heritage Administration — Important Folklore Cultural Heritage designation","Korea Cultural Heritage Foundation — Seongeup Folk Village historical records","VisitJeju — Seongeup Minsok Maeul","MBC Drama Archive — Dae Jang Geum (2003–2004) filming locations","Jeju Folklore Society — Omegisul brewing tradition documentation"]}},{"number":4,"time":"≈ 12:20","duration":"75 min","name":"Micheon Cave at Ilchul Land (Manjanggul alternate)","category":"Lava Tube + Theme Park — Manjanggul Alternate (UNESCO-property adjacent)","description":"**Ilchul Land (일출랜드)** is a **400,000 m² nature theme park** in Seongsan, opened **2002**, built around the **Micheon Cave (미천굴)** lava tube — a **1,700 m total length cave** with a **365 m artificially leveled walk-through section** open to visitors (~25-minute traverse). The cave is part of Jeju''s **lava-tube system that shares geological lineage with Manjanggul Cave** — the UNESCO World Natural Heritage lava tube — and **functions as the operational alternate when Manjanggul closes for conservation maintenance or weather (typhoons, freezing)**. Where Manjanggul preserves its uneven natural floor as an authentic geological experience, Micheon''s leveled walkway makes the cave **accessible to elderly visitors, families with strollers, and guests with mobility limitations** — a deliberate engineering choice that broadens the lava-tube experience to audiences who couldn''t navigate Manjanggul. The interior is lit with **decorative seven-color lighting (gold, silver, bronze, red, black, blue, white)** highlighting cave formations — controversial among purists but practical for non-specialist tourist photography. Outside the cave, the park extends across **Subyeon Park, a reconstructed traditional Jeju village, Wild Flower Bonsai Garden, Cactus Greenhouse, Sculpture Street, and a Footbath Cafe (aroma foot spa)** — making this the **only Jeju attraction with an on-site Muslim prayer room** (a deliberate accessibility investment). Drama filming credit: **''Running Man'' (런닝맨, SBS) Episode 89 (Alice-in-Wonderland themed, 2012)**. Admission: **Adult ₩12,000 / Youth ₩9,000 / Child ₩7,000**. Indoor/outdoor split is **30% indoor (cave + greenhouse)** / **70% outdoor (park grounds)** — meaningful for weather-flexibility planning.","image":"https://images.unsplash.com/photo-1502780402662-acc01917a3a4","highlights":["**1,700 m total** lava tube; **365 m open section** (~25-min walk-through)","**Manjanggul UNESCO alternate** — same lava-tube system; opens when Manjanggul closes","**Floor artificially leveled** — accessible to elderly, strollers, mobility-limited guests","**Seven-color decorative lighting** — gold/silver/bronze/red/black/blue/white","**400,000 m² park grounds** — bonsai, cactus, sculpture, traditional village, footbath cafe","**Only Jeju attraction with on-site Muslim prayer room** — deliberate accessibility","**''Running Man'' Ep. 89** filming (2012, Alice-in-Wonderland theme)","Admission **₩12,000 adult / ₩9,000 youth / ₩7,000 child**","**30% indoor / 70% outdoor** — weather-flexible mix"],"timeUsed":["Parking + ticket + entrance — ~5 min","Micheon Cave walk-through (365 m / ~25 min) — ~30 min","Subyeon Park + sculpture street — ~20 min","Optional bonsai/cactus garden + footbath cafe — ~15 min","Buffer / regroup — ~5 min"],"whyOnRoute":"**Pre-lunch lava-tube anchor** — explicitly framed as the **UNESCO-property adjacent** chapter of the day''s UNESCO theme. Where the nature-core sister tour uses Ilchulland as a mid-afternoon weather-flexible stop, this UNESCO-spots route positions it earlier in the day to keep the **''UNESCO + heritage'' narrative arc tight**: Hamdeok (Olle Trail 19, semi-UNESCO-status walking heritage) → Seongeup (Important Folklore Cultural Heritage) → **Ilchulland Micheon Cave (Manjanggul lava-tube system — same UNESCO property as Manjanggul itself)** → afternoon Seongsan (Triple UNESCO) → finale Haenyeo Museum (UNESCO Intangible 2016). The pre-lunch placement also ensures cave temperature comfort (caves are 13–15°C year-round — pleasantly cool in summer, mildly cool in winter) before the day''s warmest outdoor stretches.","_poi_meta":{"poi_key":"ilchulland_micheon_cave","kb_version":"1.19","verified_date":"2026-04-29","sources":["Ilchul Land official site (ilchulland.com)","VisitJeju — Ilchul Land Micheon Cave","Korea Cave Research Institute — Manjanggul lava-tube system documentation","SBS Variety Archive — Running Man Episode 89 (2012)","Jeju Tourism Organization — accessibility-friendly attraction registry"]}},{"number":5,"time":"≈ 13:35","duration":"60 min","name":"Lunch (Jeju local restaurant)","category":"Midday Reset — East Jeju Local Cuisine","description":"**60-minute reset between Ilchulland and Seongsan Ilchulbong** — Seongsan-eup harbor-side restaurant strip catches daily seafood landings. Default rotation: **mulhoe (물회, cold raw-fish soup)** in summer (June–September), **galchi-jorim (갈치조림, braised cutlassfish)** in winter (October–February), or **heuk-doeji gui (흑돼지구이, Jeju black pig BBQ)** year-round. Black pig is a heritage breed designated **Cultural Heritage Material No. 5 (2015)**. **Vegetarian + halal-friendly options** available at one venue in the rotation — disclose at pickup. Lunch venue is **10-min coach to Seongsan Ilchulbong** entrance — minimal post-lunch transit before the afternoon climb.","image":"https://images.unsplash.com/photo-1414235077428-338989a2e8c0","highlights":["**East Jeju seafood corridor** — Seongsan-eup harbor-side strip","**Mulhoe (물회)** in summer; **galchi-jorim** winter rotation","**Heuk-doeji** year-round — Cultural Heritage Material No. 5 (2015)","**Vegetarian + halal-friendly** options on request","**10-min coach to Seongsan Ilchulbong** entrance","Group dietary requirements collected at pickup"],"timeUsed":["Coach to lunch venue — ~5 min","Order + meal — ~45 min","Coach to Seongsan Ilchulbong entrance — ~10 min"],"whyOnRoute":"Seongsan-eup placement = 10-min hop to the cone climb. Mulhoe is an east-Jeju regional specialty (less common in Jeju City), so the geographic placement adds culinary identity to the lunch slot. Pace also breaks the morning''s beach + village + cave walking before the afternoon Seongsan ascent + Haenyeo Museum interior."},{"number":6,"time":"≈ 14:45","duration":"90 min","name":"Seongsan Ilchulbong (UNESCO Sunrise Peak)","category":"UNESCO Tuff Cone — Sunrise Peak (Triple UNESCO Designation)","description":"**Seongsan Ilchulbong (성산일출봉, ''Sunrise Peak'')** is a **5,000-year-old Surtseyan-type hydrovolcanic tuff cone** — a rare landform created when an underwater basalt eruption broke the sea surface, the magma met seawater, and the resulting steam-explosive ash built a **182 m fortress-shaped crater** rim instead of a typical lava cone. The result is what UNESCO formally calls **''an exceptional example of an emergent Surtseyan-type volcanic edifice''**. The crater is **600 m wide × 90 m deep**, ringed by **99 jagged rim rocks** that local lore likens to a stone crown. Seongsan carries the **Triple UNESCO designation**: **World Natural Heritage (inscribed 2007-07-02)** as part of the **''Jeju Volcanic Island and Lava Tubes'' property**, **Biosphere Reserve (2002)**, and **Global Geopark (2010-10)** — a stack matched only by Hallasan itself among Korean sites. **18 Imperial Japanese WWII caves** (kamikaze suicide-boat shelters, 1945) are tunneled into the seaward base. Trail: **0.8 km one-way, ~140 m elevation gain, 60 min round trip** on wide stone steps. **Haenyeo (해녀) demonstrations** run **daily at 13:30 and 15:00** at the rocky cove below the cone — Jeju women divers (UNESCO Intangible Cultural Heritage 2016) descend without scuba gear. Admission updated **April 2025**: **Adult ₩5,000 / Youth+Child ₩2,500 / Group adult ₩1,600**, free under 7 and over 65. The summit deck is also part of the **Yeongjusipgyeong (Jeju 10 Scenic Wonders) canon**, and remains Korea''s premier **annual New Year sunrise pilgrimage** destination — 50,000+ visitors ascend before dawn on January 1, with municipal sunrise-festival programming since 1995. **Udo Island (우도, ''Cow Island'')** — Korea''s largest secondary volcanic island — is clearly visible 4 km offshore from the summit, accessible by **15-min ferry from Seongsan Port** (₩10,500 round-trip) for guests with extra time on a different itinerary.","image":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd","highlights":["**Triple UNESCO**: World Heritage 2007-07-02 + Biosphere Reserve 2002 + Global Geopark 2010-10","**5,000 years old** — Surtseyan-type hydrovolcanic eruption, magma-meets-seawater steam-explosive birth","Crater **600 m wide × 90 m deep**, ringed by **99 jagged rim rocks** (the ''stone crown'')","**182 m above sea level** — 0.8 km / ~140 m gain, 60-min round trip on stone-step trail","**18 Imperial Japanese WWII caves** at base — 1945 kamikaze suicide-boat shelters","**Haenyeo demonstrations daily 13:30 + 15:00** at the seaside cove — UNESCO Intangible 2016","**Admission updated April 2025**: Adult ₩5,000 / Youth ₩2,500 / FREE under 7 + over 65","Spring/autumn hours **05:00–19:00** (last entry 18:20)","**Closes for first Monday of each month** (occasional rest day)"],"timeUsed":["Parking + ticket + base brief — ~10 min","Ascent to summit deck (0.8 km / 140 m gain) — ~30 min","Summit views + crater rim photos — ~20 min","Descent — ~20 min","Optional haenyeo viewing at base (15:00 demo) — ~10 min"],"whyOnRoute":"**Triple UNESCO climax of the eastern UNESCO route**. Where the nature-core sister tour places Seongsan as the day''s afternoon center (sandwiched between Seopjikoji morning and Ilchulland afternoon), this UNESCO-spots route positions Seongsan as the **day''s penultimate climactic anchor** — preceded by Hamdeok WWII history + Seongeup Joseon heritage + Ilchulland lava tube, and followed by the Haenyeo Museum UNESCO Intangible finale. The 14:45 arrival catches the **15:00 haenyeo demonstration** at the cone base — a thematically perfect bridge to the Haenyeo Museum stop next, where the same diving culture is presented in museum context. Triple UNESCO status (WHC + Biosphere + Geopark) at Seongsan + UNESCO Intangible (2016) at Haenyeo Museum = the day''s most explicit UNESCO concentration in the catalog. Spring/autumn evenings: descent timing puts guests back at coach by ~16:15, leaving 30+ min for Haenyeo Museum interior + drive back to Jeju City.","_poi_meta":{"poi_key":"seongsan_ilchulbong","kb_version":"1.19","verified_date":"2026-04-29","sources":["UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007-07-02)","UNESCO Global Geoparks Network — Jeju (2010-10 designation)","Cultural Heritage Administration — Natural Monument designation 2000-07-19","Seongsan Ilchulbong official site (seongsan.kr) — April 2025 admission update","Jeju Haenyeo Museum — UNESCO Intangible 2016 inscription record"]}},{"number":7,"time":"≈ 16:30","duration":"45 min","name":"Haenyeo Museum (women divers)","category":"UNESCO Intangible Cultural Heritage Anchor — Jeju Diving Culture (2016)","description":"**Jeju Haenyeo Museum (제주 해녀 박물관)** is the institutional anchor for **''Culture of Jeju Haenyeo (women divers)''** — inscribed as **UNESCO Intangible Cultural Heritage of Humanity in 2016**. Located in **Gujwa-eup**, the museum sits in the heart of Jeju''s most haenyeo-active eastern coastal villages. The earliest written record of Jeju women divers dates to **1629**, in **''Description of Jeju''s Natural Features'' and ''Collected Works of Guchang'' by Lee Geon (이건)**, where they were called **''Jamnyeo (潛女, diving women)''** — though oral tradition holds that the diving practice is far older, possibly **predating Joseon by centuries**. The museum documents the haenyeo''s distinctive practice across **3 exhibition halls**: **(1) Daily Life + Equipment** — traditional diving gear (pre-rubber-suit cotton suits, *tewak* gourd floats, *bitchang* hand-spear, weighted nets), kitchen tools, and the **maternal lineage of dive-teaching** (mothers train daughters from age 6–7); **(2) Diving Practice + Categorization** — haenyeo are formally graded as **Hagun (junior, trainee), Junggun (mid-level), Sanggun (senior, who guides the others)**, with depth and breath-hold capacity defining rank; senior haenyeo dive to **10 m on a single 60-second breath-hold**, working **~7 hours per day, ~90 days per year**; **(3) Community + Future** — village cooperatives, ritual songs, the **diminishing population (under 4,000 active today, mostly 70+)**, and conservation efforts. Outdoor sculpture garden + replica fishing boat at the entrance courtyard. Admission: **Adult ₩1,100 / Youth ₩500 / FREE under 7 + over 65**. Hours: **09:00–18:00**, **closed Tuesdays and lunar new year/Chuseok**. Indoor ratio ~80% — strong rainy-day fallback anchor.","image":"https://images.unsplash.com/photo-1551883040-7d23ea4f1f87","highlights":["**UNESCO Intangible Cultural Heritage of Humanity (2016)** — institutional anchor","**First written record 1629** — Lee Geon''s ''Description of Jeju'' / ''Guchang'' (recorded as ''Jamnyeo'')","**3 exhibition halls** — Daily Life, Diving Practice + Categorization, Community + Future","Senior **Sanggun** dive to **10 m on 60-sec breath-hold**, ~7 hr/day × ~90 days/year","**Hagun / Junggun / Sanggun** rank system based on depth + breath-hold capacity","**Maternal lineage** — mothers train daughters from age 6–7","**Under 4,000 active haenyeo** today — mostly 70+; population diminishing","Admission **₩1,100 adult / ₩500 youth / FREE under 7 + over 65**","Hours **09:00–18:00**, **closed Tuesdays + lunar holidays**; indoor ~80% (rain-friendly)"],"timeUsed":["Parking + entrance + ticket — ~5 min","Hall 1 (Daily Life + Equipment) — ~10 min","Hall 2 (Diving Practice + Categorization) — ~10 min","Hall 3 (Community + Future) — ~10 min","Outdoor sculpture garden + replica boat — ~5 min","Buffer + restroom — ~5 min"],"whyOnRoute":"**UNESCO Intangible heritage finale** — and the day''s narrative climax. After the morning''s natural + colonial-history layers (Hamdeok), the Joseon administrative heritage (Seongeup), the lava-tube UNESCO adjacency (Ilchulland), and the Triple UNESCO geological climax (Seongsan), the Haenyeo Museum **completes the day''s UNESCO narrative arc** with UNESCO Intangible Cultural Heritage status (2016). Geographically this is **15-min coach from Seongsan**, the natural sequencing — guests who watched the 15:00 haenyeo demonstration at Seongsan now learn the full historical and cultural depth in museum context. **Indoor ratio ~80%** = the day''s strongest rainy-day fallback anchor, also a welcome interior break after the Seongsan climb. Compared with **Jeju Folk Village Museum (themed reconstruction, ₩12,000)** or **Jeju National Museum (Jeju City center, off-route)**, the Haenyeo Museum is **₩1,100, on-route, and UNESCO-grade** — the highest yield for the day''s UNESCO theme.","_poi_meta":{"poi_key":"jeju_haenyeo_museum","kb_version":"1.19","verified_date":"2026-04-29","sources":["UNESCO Intangible Cultural Heritage — Culture of Jeju Haenyeo (2016 inscription)","Jeju Haenyeo Museum official site (haenyeo.go.kr)","VisitJeju — Haenyeo Museum","Korea Maritime History Society — Jamnyeo records (1629 onward)","Jeju Special Self-Governing Province — haenyeo population census records"]}},{"number":8,"time":"≈ 17:30","duration":"30 min","name":"Drop-off (2 points + Dongmun Market)","category":"Drop-off — Jeju City Hub Sequence","description":"**Drop-off mirrors the morning pickup** with optional Dongmun Market end-of-day stop: **Dongmun Traditional Market (동문시장)** is a 25-min coach from Haenyeo Museum and offers Jeju''s most popular evening market for **fresh seafood, Jeju tangerine products, and street-food dinner options** — guests can choose to drop here for independent dining + market shopping or continue to **Jeju City Hall** and **Jeju International Airport** drop-off points. Estimated arrival: **Dongmun Market ~17:55, City Hall ~18:10, Airport ~18:25**. Same-day evening flights from JIA (last departure ~21:30) are typically viable from this drop-off timing.","image":"https://images.unsplash.com/photo-1549144511-f099e773c147","highlights":["**3 drop-off points** — Dongmun Market, City Hall, Airport","**Dongmun Traditional Market** — Jeju''s most popular evening market, seafood + tangerine + street food","Estimated arrival: Dongmun ~17:55, City Hall ~18:10, Airport ~18:25","**Same-day evening flights from JIA** typically viable (last departure ~21:30)","Drop-off sequence aligned with morning pickup mirroring"],"timeUsed":["Coach Haenyeo Museum → Dongmun — ~25 min","Dongmun Market drop-off — 5 min","Coach to City Hall — ~10 min","City Hall drop-off — 5 min","Coach to Airport — ~15 min","Airport drop-off — 5 min"],"whyOnRoute":"Dongmun Market drop-off = optional dinner stop for guests who want to end the day with Jeju seafood + market browsing rather than coach return to hotel. City Hall + Airport drop-offs cover hotel-zone + departure-flight guests. Total post-Haenyeo Museum transit ~55 min covers all 3 points without backtracking."}],"routeFlowStops":[{"name":"Jeju City + airport pickup","type":"origin","theme":"Departure"},{"name":"Hamdeok Seoubong Beach","type":"secondary","theme":"Beach"},{"name":"Seongeup Folk Village","type":"primary","theme":"Heritage Village"},{"name":"Micheon Cave at Ilchul Land","type":"primary","theme":"Cave"},{"name":"Lunch","type":"meal","theme":"Meal"},{"name":"Seongsan Ilchulbong (UNESCO)","type":"primary","theme":"UNESCO Volcano"},{"name":"Haenyeo Museum","type":"primary","theme":"Culture"},{"name":"Jeju City drop-off","type":"return","theme":"Return"}],"routePhases":[{"phase":"Pickup & coastal opener","duration":"≈ 1 hour","description":"Multi-point pickup across Jeju City (08:30–09:05) + drive to Hamdeok Beach."},{"phase":"Coast to inland heritage","duration":"≈ 3 hours","description":"Hamdeok Beach + Seoubong (60 min), drive to Seongeup Folk Village + Joseon-era cultural assets (60 min), short transit to Micheon Cave at Ilchul Land (45 min)."},{"phase":"Lunch","duration":"≈ 1 hour","description":"Local restaurant near Pyoseon — black pork, abalone porridge, or seasonal seafood. Lunch paid separately."},{"phase":"UNESCO core","duration":"≈ 2 hours","description":"Seongsan Ilchulbong (60 min, optional rim climb) + Haenyeo Museum at Hado-ri (45 min)."},{"phase":"Return","duration":"≈ 2 hours","description":"Hado-ri → Jeju City drive (≈ 50 min) + drop-off across 2 points and Dongmun Market (≈ 40 min)."}],"routeShapeIntro":{"title":"How this day flows","subtitle":"An eastern-Jeju loop covering the island''s two UNESCO highlights from the east — Seongsan Ilchulbong (Natural Heritage) and the Haenyeo women-diver tradition (Intangible Cultural Heritage) — plus the heritage anchor of Seongeup Folk Village and the Micheon Cave lava tube as the current Manjanggul alternate. The 4.9/5 rating across 1,148 reviews is the highest of the operator''s tour family, and the all-admissions-included structure (Seongsan ₩5,000, Seongeup, Micheon Cave, Haenyeo Museum) saves visitors approximately ₩20,000 vs. paying à la carte."},"whyTourWorks":{"bestFor":["First-time visitors to the area","Couples","Adult families","Active travelers comfortable with full days","Travelers who want UNESCO World Heritage stops"],"lessIdealFor":["Travelers who want minimal walking","Stroller-heavy groups","Travelers needing a tight same-day flight buffer"],"routeLogicSections":[{"title":"Why this route is built this way","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"Both UNESCO listings (natural + cultural) in one day","detail":"Most Jeju eastern tours include Seongsan Ilchulbong but skip the Haenyeo Museum. This route deliberately keeps both — meaning visitors leave with both Jeju UNESCO categories: the natural heritage (Seongsan''s tuff cone) and the intangible cultural heritage (haenyeo women-diver tradition, listed 2016)."},{"label":"Manjanggul alternate handled gracefully","detail":"Manjanggul Lava Tube is currently closed — most tours either skip cave content entirely or substitute lazily. This route uses Micheon Cave at Ilchul Land, which gives visitors a comparable lava-tube experience plus the Ilchul Land botanical garden (seasonal flower displays). When Manjanggul reopens, the operator will likely revert; check at booking."},{"label":"All admissions included — value at the price tier","detail":"Eastern Jeju has more paid attractions than southern Jeju (Seongsan ₩5,000, Ilchul Land ₩12,000, Haenyeo Museum ₩1,100). Including all of them in the base price saves ≈ ₩18,000 per person versus the standard à-la-carte structure of competing tours."},{"label":"Seongsan Ilchulbong is optional-climb","detail":"The 30-minute rim climb is steep and not for everyone. The route allocates 90 minutes total at the site, which is enough for the climb if you want it but also enough to walk the free coastal trail at the base for similar photo angles without the stairs. Visitors with mobility concerns get the UNESCO credit either way."}]}]},"practicalAccordionItems":[{"id":"inclusions","title":"What''s included","preview":"Air-conditioned mini-coach, certified English/Chinese-speaking guide, ALL attraction…","content":["Air-conditioned mini-coach, certified English/Chinese-speaking guide, ALL attraction admissions (Seongsan Ilchulbong ₩5,000, Seongeup Folk Village free, Ilchul Land/Micheon Cave ₩12,000, Haenyeo Museum ₩1,100, Hamdeok Beach free), fuel/tolls/parking.","Not included: lunch (≈ ₩15,000), drinks, tips."]},{"id":"pickup","title":"Pickup & drop-off","preview":"Sequential pickup at four points: Ocean Suites Jeju (08:30), Jeju Airport Gate 1, 1F…","content":["Sequential pickup at four points: Ocean Suites Jeju (08:30), Jeju Airport Gate 1, 1F Domestic Arrivals (08:45 — note: different gate from operator''s Southern tour), LOTTE City Hotel Jeju (08:55), Shilla Duty-Free Jeju Store (09:05).","Choose the closest at booking.","Day-before WhatsApp confirmation."]},{"id":"walking","title":"Walking & terrain","preview":"Moderate.","content":["Moderate.","Hamdeok Beach is flat sand.","Seongeup Folk Village has dirt paths and stone walls.","Micheon Cave has stairs descending into the tube and uneven flooring inside.","Seongsan Ilchulbong''s rim climb is 30 minutes of steep stone steps (skippable).","Haenyeo Museum is flat indoor walking.","Comfortable closed-toe shoes essential.","Total walking ≈ 4–5 km."]},{"id":"cancellation","title":"Cancellation","preview":"Free cancellation up to 24 hours before pickup.","content":["Free cancellation up to 24 hours before pickup.","Same-day cancellations and no-shows non-refundable.","Heavy weather may shorten the Seongsan climb but does not cancel the day."]},{"id":"cave","title":"Cave note (Manjanggul status)","preview":"Manjanggul Lava Tube is currently closed for safety repairs (unscheduled reopening).","content":["Manjanggul Lava Tube is currently closed for safety repairs (unscheduled reopening).","The Micheon Cave at Ilchul Land is the standard alternate and is included on this route.","If Manjanggul reopens during your travel period, the operator may swap stops; check at booking."]},{"id":"children","title":"Children & accessibility","preview":"Recommended for ages 10+ due to the Seongsan Ilchulbong rim climb (≈ 600 stairs, optional…","content":["Recommended for ages 10+ due to the Seongsan Ilchulbong rim climb (≈ 600 stairs, optional but the day''s centerpiece) and a 9-hour pace.","Younger children can join, but the climb may be too much; consider our year-round Cherry Blossom or Cruise Bus tours which skip the summit.","Strollers are not recommended on Seongsan stairs or Seongeup village paths."]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"See seasonal notes"},"tomorrow":{"temp":"—","label":"See seasonal notes"},"_seasonalSummary":"Eastern Jeju has the cleanest sea views on the island and the warmest summer temperatures. Seongsan Ilchulbong is exposed to wind year-round; bring a light layer.","_seasonalTemperatures":[{"season":"Spring (Mar–May)","range":"8–22°C","notes":"Cherry blossoms in early April; rapeseed flowers on Hamdeok''s Seoubong cone."},{"season":"Summer (Jun–Aug)","range":"22–30°C","notes":"Hot but breezy at coastal stops. Best ocean colors at Hamdeok."},{"season":"Autumn (Sep–Nov)","range":"10–24°C","notes":"Best season — clearest visibility for Seongsan rim views."},{"season":"Winter (Dec–Feb)","range":"3–10°C","notes":"Wind chill significant at Seongsan rim. Fewer crowds at all stops."}]},"seasonalVariations":[{"season":"Spring","description":"Rapeseed (canola) flowers on Hamdeok''s Seoubong cone slopes — striking yellow against emerald sea."},{"season":"Summer","description":"Best sea colors at Hamdeok Beach; long daylight for Seongsan visit."},{"season":"Autumn","description":"Clearest visibility for Seongsan rim panoramas; Seongeup village stays photogenic year-round."},{"season":"Winter","description":"Quietest crowds; Haenyeo Museum particularly valuable in cold weather."}],"bookingTrustItems":[{"icon":"check-circle","title":"Licensed local operator","description":"Authorized Korean tour operator with full insurance","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Route specialists","description":"Hand-tuned itinerary, not a generic loop","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Curated group size","description":"Right-sized for the route","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"Immediately","title":"Instant Confirmation","detail":"Booking confirmation with itinerary summary"},{"timing":"12 hours before","title":"12-Hour Reminder","detail":"Weather update and any route adjustments"},{"timing":"Evening before","title":"Final Pickup Info","detail":"Exact pickup time and driver contact"},{"timing":"Morning of tour","title":"Day-of Route Notes","detail":"Morning briefing based on live conditions"},{"timing":"During tour","title":"Stop-by-Stop Tips","detail":"Real-time guidance at each location"},{"timing":"After tour","title":"Post-tour Support","detail":"Follow-up and recommendations"}],"staticQuestions":[{"id":"q1","question":"Will I see live haenyeo divers?","answer":"The Haenyeo Museum has video footage of working dives. Live diving demonstrations sometimes happen at the adjacent harbor or at Seongsan Ilchulbong''s base (typically 13:30 and 15:00 daily, weather-permitting). The tour timing increases the chance but does not guarantee a live demonstration."},{"id":"q2","question":"Can I skip the Seongsan rim climb?","answer":"Yes — the free coastal trail at the base offers similar photo angles without the stairs. The 90-minute stop window accommodates either choice. Visitors with mobility concerns or who prefer a calmer pace use the coastal trail."},{"id":"q3","question":"How is this different from the Southern UNESCO tour?","answer":"Same operator. The Southern tour covers Hallasan trail, Camellia Hill, Cheonjeyeon Falls, Jusangjeolli, O''sulloc — focused on natural heritage and gardens. This Eastern tour covers Hamdeok Beach, Seongeup Village, Micheon Cave, Seongsan, and the Haenyeo Museum — focused on UNESCO heritage (both natural and cultural) and traditional Jeju life. Most 2-day Jeju visitors do one of each."},{"id":"q4","question":"What if Manjanggul reopens during my visit?","answer":"If Manjanggul (a more famous and longer lava tube than Micheon) reopens, the operator may swap the cave stop. Manjanggul is currently closed for ongoing safety repairs with no announced reopening date — the Micheon Cave alternate is the dependable substitute."},{"id":"q5","question":"Is lunch included?","answer":"No — lunch is at your own expense (≈ ₩15,000). The guide will recommend a local east-Jeju restaurant and assist with vegetarian, vegan, halal, or allergy needs if you advise at booking."},{"id":"q6","question":"Why airport Gate 1 instead of Gate 3?","answer":"The Eastern tour pickup uses Jeju Airport Gate 1 (1st Floor Domestic Arrivals) because the airport-to-east-coast route is more efficient via the eastern airport perimeter road. The Southern tour uses Gate 3 (3rd Floor Domestic Departures) for the southern route. This is operational; pick whichever tour is in your plan and follow the gate listed on your booking."},{"id":"first-time","question":"Is this a good choice for first-time visitors to eastern Jeju?","answer":"Yes — it covers the most distinctive stops in the area in a single balanced day."},{"id":"walking","question":"Is the walking difficult?","answer":"An active day with several walking-heavy stops."},{"id":"family","question":"Is this tour suitable for families?","answer":"Yes for families whose kids can handle a full day of moving around."},{"id":"seniors","question":"Can older adults join comfortably?","answer":"Recommended only for active seniors comfortable with stairs and uneven ground."},{"id":"children","question":"What''s the recommended minimum age?","answer":"Best fit is around age 10 and up — children comfortable with a full-day rhythm and the walking notes above."}],"guestReviews":[],"reviewsSummary":{"averageRating":4.9,"totalReviews":1148,"ratingDistribution":[{"stars":5,"count":1056,"percentage":92},{"stars":4,"count":69,"percentage":6},{"stars":3,"count":15,"percentage":1.3},{"stars":2,"count":6,"percentage":0.5},{"stars":1,"count":2,"percentage":0.2}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"","currency":"USD","per":"person","priceSource":"getyourguide_t608456","priceNote":"Small-group price not yet confirmed from listing snippet. Sister product (Southern UNESCO, same operator) is $43 per person; this Eastern tour is comparable. Once confirmed, AtoC Korea sale price applies a flat 10% discount.","discountPercent":10}},"pickup_dropoff":{"type":"meeting_point","meeting_points":[{"name":"Ocean Suites Jeju Hotel","time":"08:30"},{"name":"Jeju International Airport Gate 1, 1st Floor (Domestic Arrivals)","time":"08:45"},{"name":"LOTTE City Hotel Jeju","time":"08:55"},{"name":"Shilla Duty-Free Jeju Store","time":"09:05"}],"dropoff_points":[{"name":"Shilla Duty-Free Jeju Store","approx_time":"≈ 17:45"},{"name":"Dongmun Traditional Market (drop-only)","approx_time":"≈ 18:00"}],"hotel_pickup_available":false,"notes":"Note: air