u","unesco_focused","haenyeo_culture","world_heritage","intangible_heritage","joseon_heritage"],"secondary_themes":["top_3_beach","wwii_colonial_history","lava_tube","feng_shui_walled_town","tuff_cone","olle_trail","k_drama_filming"],"best_for":["first_time_jeju","unesco_focused_travelers","history_lovers","couples","small_families","senior_couples","rainy_day_visitors","guests_with_evening_flights"],"not_recommended_for":["thrill_seekers","private_tour_seekers","guests_demanding_west_jeju_coverage","wheelchair_users_unable_to_climb_seongsan","checkbox_sightseers_avoiding_museums"],"anchor_pois":["Hamdeok Seoubong Beach","Seongeup Folk Village","Ilchul Land (Micheon Cave)","Seongsan Ilchulbong","Jeju Haenyeo Museum"],"anchor_poi_keys":["hamdeok_seoubong_beach","seongeup_folk_village","ilchulland_micheon_cave","seongsan_ilchulbong","jeju_haenyeo_museum"],"reviews_attribution":"Aggregate rating 4.9/5 (1,148 reviews) from the operator''s GetYourGuide listing. Individual review snippets are not pulled into this catalog; users see the summary metric on this page and can read full reviews on the operator''s GYG listing.","unesco_fit_note":"unesco_fit=5 = 1 WHS (Seongsan Ilchulbong, inscribed 2007) + 1 Intangible Cultural Heritage of Humanity (Culture of Jeju Haenyeo, inscribed 2016, accessed via the Haenyeo Museum stop). Seongeup Folk Village is Korea''s national folk heritage — NOT UNESCO — and does not contribute to this score.","_internal_competing_products_note":"Comp set (internal only): Southern UNESCO sister product, same operator, $43/pax small-group rate as ceiling reference.","competing_products":["east-signature-nature-core","jeju-grand-highlights-loop","jeju-southern-top-unesco-spots-tour"],"audit_summary":"East Jeju UNESCO-focused loop covering 5 distinct UNESCO heritage layers in one day: Olle Trail walking heritage (Hamdeok Course 19), Important Folklore Cultural Heritage (Seongeup Folk Village 1423 founding), Manjanggul-system lava tube (Ilchulland — UNESCO-property adjacent), Triple UNESCO Surtseyan tuff cone (Seongsan Ilchulbong), and UNESCO Intangible Cultural Heritage of Humanity (Jeju Haenyeo Museum, 2016 inscription). UNESCO-anchored counterpart to the signature-nature sister tour, which emphasizes Seolmundae Halmang mythology + Tadao Ando architecture instead.","score_rationale":{"high_scores":{"unesco_focused_tour_fit=1.0":"5 explicit UNESCO heritage layers in one day — densest UNESCO concentration in catalog","haenyeo_culture_fit=1.0":"UNESCO Intangible 2016 — full museum context + Seongsan demonstration in same day","rainy_day_friendly_fit=1.0":"3 indoor fallback anchors (Seongeup hanok + Ilchulland cave + Haenyeo Museum 80% indoor)","value_priced_fit=0.95":"Total ₩18,100 admission per adult for 5 UNESCO-grade anchors = catalog-leading UNESCO value","feminist_history_fit=0.95":"Haenyeo Museum is the catalog''s strongest women''s-labor heritage anchor","wwii_history_fit=1.0":"Hamdeok tunnels + Seongsan 18 caves both visible in day''s narrative arc"},"low_scores":{"private_tour_fit=0.05":"Format is small-group fixed itinerary only","west_jeju_fit=0.05":"Loop deliberately east-anchored","language_japanese_fit=0.55":"WWII/colonial-history framing slightly sensitive for Japanese guests — guide trained for context"}},"differentiation_vs_signature_nature_sister":"Same Seongsan + Seongeup + Ilchulland anchors, but **UNESCO-anchored framing** (Hamdeok Olle 19 + Haenyeo Museum UNESCO Intangible 2016) vs. sister''s **mythology + architecture framing** (Jeju Stone Park Seolmundae + Seopjikoji Tadao Ando). This tour = 5 UNESCO heritage layers + strongest rain-friendly anchor count + best ₩-per-UNESCO-anchor value; sister = mythology + Pulitzer architecture + 4 K-drama filming sites. Pair complementarily for guests with 2 days on Jeju.","seasonal_window":{"best_months":["April","May","June (Hamdeok beach)","September","October"],"good_months":["March","July","August (peak beach)"],"caveat_months":["December","January (Seongsan ice)"],"peak_crowd_months":["July","August (Hamdeok summer peak)"]},"kb_anchor_version":"1.19"},"itinerary_variants":[],"_publication":{"schema_version":"v4_canonical","last_modified":"2026-04-28","version_history":["v11","v12","v13","v14","v15","v15.2"],"fix_passes":{"v12":"P0+P1 — pickup_dropoff Schema A unification, routeFlowStops type-based, competing_products → internal slugs, anchor_poi_keys aligned","v13":"P1.5 — pickup_dropoff Schema A.2 → A.1; practicalAccordionItems / routePhases / seasonalVariations unified to V4 canonical (no Tailwind in data)","v14":"P2 — _publication uniform; duration formatting standardized; glanceItems Duration added where missing","v15":"P3 round 1 — SEO trim. seo.pageTitle rewritten to ≤65 chars (was 14/25 over 70); seo.metaDescription rewritten to ≤168 chars (was 25/25 over 170). primaryKeywords and ogImage unchanged. Hero/OG images, POI verification, review imports, and routePhases enrichment deferred to later P3 rounds.","v15.2_charter_consolidation":"Removed \"jeju-popular-sightseeing-private-car-charter-tour\" from competing_products per Jason''s one-charter-per-region rule (jeju-island-private-car-charter-tour remains as canonical Jeju charter).","v17_schema_unification":{"date":"2026-04-28","description":"Phase 1: Converted matching_profile scores from 1-5 int scale to 0-1 float scale to match the 3 Step 3 new tours. Mapping 1→0.20, 2→0.40, 3→0.60, 4→0.80, 5→1.00. Mechanical conversion preserves ordinal information; verified-fact recalibration happens in subsequent enhancement batches.","fields_converted":43,"fields_skipped":0,"fields_already_float":0},"v17_batch2_enhancement":{"date":"2026-04-28","description":"Batch 2 deep enhancement — descriptions raised to 700-1100+ chars; KB-backed visitBasics/convenience/smartNotes/_poi_meta on all attraction stops; matching_profile recalibrated with verified-fact 0-1 float scores (replacing Phase 1 mechanical conversion).","_score_audit":{"_methodology":"0-1 float scale. Each score grounded in verified facts.","deltas_applied":{"unesco_fit":{"old":1,"new":1,"reasoning":"VERIFIED 1.0 — this tour is correctly named ''eastern UNESCO loop'': Seongsan = UNESCO World Heritage (Jeju Volcanic Island & Lava Tubes 2007), Haenyeo Museum = UNESCO Intangible Cultural Heritage (haenyeo culture 2016). Tour covers BOTH UNESCO categories. Strongest UNESCO-fit tour in catalogue."},"intangible_heritage_fit":{"old":1,"new":1,"reasoning":"VERIFIED 1.0 — Haenyeo Museum is the dedicated UNESCO ICH interpretation center; Seongsan haenyeo demonstrations 13:30/15:00 are live UNESCO ICH performance; Seongeup Folk Village preserves Joseon-period intangible folkways. 3 of 5 attractions carry intangible-heritage value. Highest possible score."},"walking_level":{"old":0.8,"new":0.65,"reasoning":"DOWNGRADED 0.8→0.65 with verified totals: Hamdeok beach 0.5 km flat (sand + boardwalk), Seongeup ~1 km flat olle, Micheon Cave 365 m flat (leveled), Seongsan 0.8 km + 140 m gain (the only stair-heavy stop), Haenyeo Museum 100% indoor flat. Total ~3 km + only Seongsan has elevation. Tour 1 (east-signature) walks more (Seopjikoji 2.1 km extra). Verified moderate walking = 0.65 not 0.8."},"young_kids_fit":{"old":1,"new":0.75,"reasoning":"DOWNGRADED 1.0→0.75: Hamdeok beach + leveled Micheon Cave + indoor Haenyeo Museum + Seongeup folk village = 4 of 5 kid-friendly. ONLY Seongsan''s 300-500 steps challenge under-7s. Mechanical 1.0 was overstated; verified 0.75 is honest."},"stroller_fit":{"old":0.4,"new":0.5,"reasoning":"UPGRADED 0.4→0.50: Hamdeok flat + Micheon Cave LEVELED FLOOR (verified — vs Manjanggul''s uneven natural floor) + Haenyeo Museum 100% accessible + Seongeup main alleys + ONLY Seongsan stairs unsuitable. 4/5 stroller-friendly = 0.50 not the previous 0.4. Specifically chose Micheon vs Manjanggul for accessibility."},"mobility_friendly_fit":{"old":0.6,"new":0.65,"reasoning":"UPGRADED 0.6→0.65: Verified 4 of 5 stops mobility-friendly (Hamdeok flat, Micheon leveled, Haenyeo Museum elevators, Seongeup flat alleys), only Seongsan summit not accessible. The choice of Micheon Cave instead of Manjanggul specifically supports this."},"weather_sensitivity":{"old":1,"new":0.75,"reasoning":"DOWNGRADED 1.0→0.75 — verified: Haenyeo Museum 100% indoor, Micheon Cave 100% indoor and stable temperature year-round, Seongeup hanok have shelter. Only Hamdeok and Seongsan are weather-exposed. The ''all UNESCO'' name made the prior score look high, but indoor ratio is actually reasonable. Mechanical 1.0 overstated."},"indoor_ratio":{"old":0.1,"new":0.4,"reasoning":"MAJOR CORRECTION: Verified breakdown — Hamdeok 100% outdoor, Seongeup ~30% indoor (visiting hanok interiors), Micheon Cave 100% indoor, Seongsan 5% indoor (visitor center only), Haenyeo Museum 100% indoor. Time-weighted indoor ratio ~40%, NOT the previous 10%. Correcting a documentation error."},"rain_fit":{"old":0.6,"new":0.75,"reasoning":"UPGRADED 0.6→0.75: With Micheon Cave (indoor), Haenyeo Museum (indoor), and Seongeup hanok interiors as rain refuges, this tour holds up MUCH better in rain than the mechanical 0.6 implied. Hamdeok and Seongsan suffer in rain but the rest is fine. Verified."},"iconic_landmark_fit":{"old":1,"new":0.85,"reasoning":"VERIFIED 0.85: Seongsan = universally iconic (triple UNESCO crown). Hamdeok = Top 3 Jeju beach. Seongeup + Haenyeo Museum = nationally significant culture (UNESCO ICH for Haenyeo). Micheon Cave = secondary lava tube. 0.85 — strong but not all 5 universally iconic."},"value_for_money_fit":{"old":1,"new":0.85,"reasoning":"Verified fees: Hamdeok free + Seongeup free + Micheon ₩12,000 + Seongsan ₩2,000 + Haenyeo Museum ₩1,100 = ~₩15,100/adult. Reasonable but Ilchul Land at ₩12,000 is the big driver. 0.85 calibrated."},"senior_fit":{"old":0.4,"new":0.55,"reasoning":"UPGRADED 0.4→0.55: With Hamdeok beach walk (flat), Micheon leveled cave, Seongeup flat alleys, Haenyeo Museum accessible — 4 of 5 stops fully senior-accessible. Only Seongsan summit excludes seniors with mobility issues (alternative: stay at base for haenyeo demo). Verified ≥0.55, much better than 0.4."},"senior_active_fit":{"old":0.6,"new":0.75,"reasoning":"UPGRADED 0.6→0.75: For active seniors, all 5 stops are achievable (Seongsan rest stops + benches make 45-60 min summit reasonable). Cultural depth (UNESCO + 600-year village + 400-year haenyeo tradition) very strong appeal for senior travelers. 0.75 verified."},"senior_general_fit":{"old":0.4,"new":0.55,"reasoning":"UPGRADED 0.4→0.55: Same logic — 4/5 stops accessible to general senior population (alternative for Seongsan = stay at base for haenyeo demonstration). 0.55 calibrated."},"beach_fit":{"old":0.6,"new":0.85,"reasoning":"UPGRADED 0.6→0.85: Hamdeok IS the dedicated beach stop — Top 3 Jeju beach (verified VisitKorea ranking). 0.6 understates this; 0.85 reflects beach as a primary tour theme."},"culture_level":{"old":1,"new":0.95,"reasoning":"Slight DOWNGRADE 1.0→0.95: Verified 3 strong cultural anchors (Seongeup 600-year town + Haenyeo 400-year tradition + Seongsan haenyeo demo). Hamdeok is recreational not cultural. 0.95 (vs east-signature''s lower) — still very strong."}}},"stops_enhanced":6,"sources":["VisitKorea","Wikipedia","UNESCO","Visit Jeju","Inside Jeju","Jeju Tourism Organization","AllTrails"]},"v17_fix1_indoor_ratio_correction":{"date":"2026-04-28","description":"Jason correction: Micheon Cave and Seongeup Folk Village are 70% outdoor. Recalculated tour-level indoor_ratio with time-weighted attraction durations and adjusted dependent fields.","computation":{"stops_time_weighted":{"hamdeok_seoubong_beach":"45min × 0.00 indoor = 0.00","seongeup_folk_village":"75min × 0.30 indoor = 22.50 (corrected from 0.50)","ilchulland_micheon_cave":"60min × 0.30 indoor = 18.00 (corrected from 0.60)","seongsan_ilchulbong":"90min × 0.05 indoor = 4.50","jeju_haenyeo_museum":"60min × 1.00 indoor = 60.00","total_indoor_min":105,"total_substantive_min":330,"computed_indoor_ratio":0.32}},"changes":{"indoor_ratio":{"old":0.4,"new":0.3,"reason":"Recalculated 105/330 = 0.32, rounded to 0.30"},"rain_fit":{"old":0.75,"new":0.55,"reason":"Only Haenyeo Museum is full refuge; Seongeup and Micheon mostly outdoor; Hamdeok and Seongsan rain-bad"},"weather_sensitivity":{"old":0.75,"new":0.7,"reason":"Still has Haenyeo Museum as anchor refuge but 70% of stop time is weather-exposed"}}}}}}'::jsonb
